import { useEffect, useRef, useState } from "react";
import { motion } from "framer-motion";

const LOGOS = [
  { title: "IMA Labeling", src: "data:image/png;base64," },
  // { title: "HP", src: "data:image/png;base64," },
  { title: "MM International", src: "data:image/png;base64," },
];


const PartnerBrands = () => {
  const [index, setIndex] = useState(0);
  const [isMobile, setIsMobile] = useState(false);
  const timerRef = useRef<number | null>(null);
  const touchStartX = useRef(0);

  // LOGOS assume kiya hai upar ya niche defined hoga array
  const total = LOGOS.length;

  const goTo = (i: number) => {
    setIndex(((i % total) + total) % total);
  };

  const stopAuto = () => {
    if (timerRef.current !== null) {
      window.clearInterval(timerRef.current);
      timerRef.current = null;
    }
  };

  const startAuto = () => {
    stopAuto();
    timerRef.current = window.setInterval(() => {
      setIndex((prev) => (prev + 1) % total);
    }, 3000);
  };

  useEffect(() => {
    const checkMobile = () => setIsMobile(window.innerWidth <= 640);
    checkMobile();
    window.addEventListener("resize", checkMobile);
    return () => window.removeEventListener("resize", checkMobile);
  }, []);

  useEffect(() => {
    if (isMobile) {
      startAuto();
    } else {
      stopAuto();
    }
    return () => stopAuto();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isMobile]);

  const handleTouchStart = (e: React.TouchEvent) => {
    touchStartX.current = e.touches[0].clientX;
    stopAuto();
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    const dx = e.changedTouches[0].clientX - touchStartX.current;
    if (Math.abs(dx) > 40) {
      if (dx < 0) {
        goTo(index + 1);
      } else {
        goTo(index - 1);
      }
    }
    if (isMobile) startAuto();
  };

  const handleDotClick = (i: number) => {
    goTo(i);
    startAuto();
  };

  // ── DESKTOP LAYOUT DYNAMIC MANAGER ──
  // Agar logos 3 se kam hain, toh flex lagao aur center karo, agar 3 ya zyada hain toh normal grid!
  const desktopLayoutClass = total < 3 
    ? "flex justify-center items-center gap-6 max-w-[580px] mx-auto" 
    : "grid grid-cols-3 gap-5 w-full";

  return (
    <section className="relative bg-white py-20 px-5 overflow-hidden">
      <div className="max-w-7xl mx-auto">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6 }}
          className="text-center mb-12"
        >
          <h2 className="font-display font-bold text-4xl sm:text-4xl text-[#1E1951]">
            Our Partner Brands
          </h2>
        </motion.div>

        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.6, delay: 0.1 }}
          className="max-w-[860px] mx-auto overflow-hidden relative"
          onTouchStart={handleTouchStart}
          onTouchEnd={handleTouchEnd}
        >
          <div
            className={
              isMobile
                ? "flex w-full transition-transform duration-[600ms] ease-[cubic-bezier(0.65,0,0.35,1)]"
                : desktopLayoutClass
            }
            style={
              isMobile
                ? { transform: `translateX(-${index * 100}%)` }
                : undefined
            }
          >
            {LOGOS.map((logo) => (
              <div
                key={logo.title}
                title={logo.title}
                className={
                  "bg-white border border-gray-200 rounded-xl flex items-center justify-center px-5 py-3.5 shadow-sm transition-all duration-300 hover:-translate-y-1 hover:shadow-lg cursor-default h-[110px] " +
                  (isMobile ? "w-full flex-shrink-0 basis-full mx-auto" : "w-full max-w-[260px]")
                }
              >
                <img
                  src={logo.src}
                  alt={logo.title}
                  loading="lazy"
                  className={
                    "max-w-full w-auto h-auto object-contain block " +
                    (logo.title === "HP"
                      ? "max-h-24"
                      : logo.title === "MM International"
                      ? "max-h-[5.5rem]"
                      : "max-h-12")
                  }
                />
              </div>
            ))}
          </div>
        </motion.div>

        {isMobile && (
          <div className="flex justify-center gap-2 mt-6">
            {LOGOS.map((_, i) => (
              <span
                key={i}
                onClick={() => handleDotClick(i)}
                className={
                  "h-2 rounded-full bg-border transition-all duration-300 cursor-pointer " +
                  (i === index ? "w-[22px] bg-orange" : "w-2")
                }
              />
            ))}
          </div>
        )}
      </div>
    </section>
  );
};

export default PartnerBrands;